Here is a script using HTML and JavaScript. This code creates a form that allows you to enter text and "registers" it by saving it to the browser's local storage. You can save this code as an `.html` file and open it in any web browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Text Registration Form</title>
    <style>
        body { font-family: sans-serif; padding: 20px; }
        form { display: flex; flex-direction: column; max-width: 400px; }
        textarea { margin-bottom: 10px; padding: 8px; }
        button { padding: 10px; cursor: pointer; }
        #confirmationMessage { margin-top: 15px; color: green; }
    </style>
</head>
<body>

    <h1>Text Registration Form</h1>
    <p>Enter text below and click the button to register it.</p>

    <form id="textForm">
        <label for="textInput">Your Text:</label>
        <textarea id="textInput" name="textInput" rows="5" required></textarea>
        <button type="submit">Register Text</button>
    </form>

    <div id="confirmationMessage"></div>

    <script>
        // Select the form and the confirmation message element
        const form = document.getElementById('textForm');
        const confirmationMessage = document.getElementById('confirmationMessage');

        // Add an event listener for the form submission
        form.addEventListener('submit', function(event) {
            // Prevent the default form action (which is to reload the page)
            event.preventDefault();

            // Get the text from the textarea
            const textToRegister = document.getElementById('textInput').value;

            // "Register" the text by saving it to the browser's local storage
            // You can view this in your browser's developer tools under Application > Local Storage
            localStorage.setItem('registeredText', textToRegister);

            // Display a success message to the user
            confirmationMessage.textContent = 'Text has been registered successfully!';

            // Optional: Clear the form after submission
            form.reset();

            // Optional: Hide the message after a few seconds
            setTimeout(() => {
                confirmationMessage.textContent = '';
            }, 3000);
        });
    </script>

</body>
</html>
```
